mapper.select:

where ur.del_flag = '0'
  and rt.del_flag = '0'
  and ur.user_rights_id = #{userRightsId}
  and ur.owner_type = #{ownerType}
  and ur.owner_id = #{ownerId}


where ur.del_flag = '0'
  and rt.del_flag = '0'
  and ur.user_rights_id = #{userRightsId}
  and ur.owner_type = #{ownerType}
  and ur.owner_id = #{ownerId}
for update

select wr.record_id as recordId, ur.user_rights_id as rightsId, rt.rights_template_id as rightsTemplateId, rt.rights_name as rightsName, rt.rights_type as rightsType, wr.writeoff_no as writeoffNo, wr.use_amount as amount, wr.apply_remark as remark, wr.status as status, wr.audit_user_id as auditUserId, wr.audit_remark as auditRemark, wr.writeoff_time as auditTime, wr.create_time as applyTime from jst_rights_writeoff_record wr inner join jst_user_rights ur on ur.user_rights_id = wr.user_rights_id inner join jst_rights_template rt on rt.rights_template_id = ur.rights_template_id where wr.del_flag = '0' and ur.del_flag = '0' and rt.del_flag = '0' and ur.owner_type = #{ownerType} and ur.owner_id = #{ownerId}
and wr.user_rights_id = #{userRightsId}
and wr.status in ('used', 'expired', 'rolled_back')
and wr.status = #{status}
order by wr.create_time desc, wr.record_id desc
